{"rawEvent":{"message_id":"019daf33bfb67bcc856c71c4ae624ea3","conversation_id":"019daf322571731aacd327310d88136c","tool_call_id":"call_b995e678-2bc8-49d1-b16f-309ba68c625a","document":{"file_path":"/Users/jiangdadong/CLionProjects/webrtc_server_demo/main.cpp","sub_content":"main.cpp","sub_content_event":"open_editor","sub_content_event_value":"/Users/jiangdadong/CLionProjects/webrtc_server_demo/main.cpp","sub_content_tip":"/Users/jiangdadong/CLionProjects/webrtc_server_demo/main.cpp","apply_content":"#include <websocketpp/config/asio_no_tls.hpp>
#include <websocketpp/server.hpp>
#include <iostream>
#include <map>
#include <set>
#include <functional>
#include <thread>
#include <mutex>

using namespace websocketpp;
using namespace std;

typedef server<config::asio> server_type;

typedef server_type::message_ptr message_ptr;

// 房间管理类
class RoomManager {
public:
 void joinRoom(const string& roomId, connection_hdl hdl) {
 lock_guard<mutex> lock(mutex_);
 rooms_[roomId].insert(hdl);
 cout << "用户加入房间: " << roomId << ", 当前用户数: " << rooms_[roomId].size() << endl;
 }

 void leaveRoom(const string& roomId, connection_hdl hdl) {
 lock_guard<mutex> lock(mutex_);
 rooms_[roomId].erase(hdl);
 if (rooms_[roomId].empty()) {
 rooms_.erase(roomId);
 }
 cout << "用户离开房间: " << roomId << ", 剩余用户数: " << rooms_[roomId].size() << endl;
 }

 set<connection_hdl> getRoomUsers(const string& roomId) {
 lock_guard<mutex> lock(mutex_);
 return rooms_[roomId];
 }

private:
 map<string, set<connection_hdl>> rooms_;
 mutex mutex_;
};

class SignalingServer {
public:
 SignalingServer() {
 // 初始化服务器
 server_.init_asio();
 server_.set_reuse_addr(true);

 // 设置处理器
 server_.set_open_handler(bind(&SignalingServer::onOpen, this, placeholders::_1));
 server_.set_close_handler(bind(&SignalingServer::onClose, this, placeholders::_1));
 server_.set_message_handler(bind(&SignalingServer::onMessage, this, placeholders::_1, placeholders::_2));
 }

 void run(uint16_t port) {
 cout << "启动WebRTC信令服务器，端口: " << port << endl;
 server_.listen(port);
 server_.start_accept();
 server_.run();
 }

private:
 void onOpen(connection_hdl hdl) {
 cout << "新的WebSocket连接建立" << endl;
 }

 void onClose(connection_hdl hdl) {
 cout << "WebSocket连接关闭" << endl;
 // 从所有房间中移除用户
 for (auto& room : roomManager_.getAllRooms()) {
 roomManager_.leaveRoom(room, hdl);
 }
 }

 void onMessage(connection_hdl hdl, message_ptr msg) {
 try {
 string payload = msg->get_payload();
 cout << "收到消息: " << payload << endl;

 // 解析JSON消息（这里简化处理，实际应该使用JSON库）
 if (payload.find("\"type\":\"join\"") != string::npos) {
 // 加入房间
 size_t roomStart = payload.find("\"roomId\":\"") + 10;
 size_t roomEnd = payload.find("\"", roomStart);
 string roomId = payload.substr(roomStart, roomEnd - roomStart);

 roomManager_.joinRoom(roomId, hdl);

 // 发送确认消息
 string response = "{\"type\":\"joined\",\"roomId\":\"" + roomId + "\"}";
 server_.send(hdl, response, frame::opcode::text);

 } else if (payload.find("\"type\":\"offer\"") != string::npos) {
 // 转发offer给房间内其他用户
 forwardToRoomUsers(hdl, payload, "offer");

 } else if (payload.find("\"type\":\"answer\"") != string::npos) {
 // 转发answer给房间内其他用户
 forwardToRoomUsers(hdl, payload, "answer");

 } else if (payload.find("\"type\":\"ice-candidate\"") != string::npos) {
 // 转发ICE候选信息
 forwardToRoomUsers(hdl, payload, "ice-candidate");
 }

 } catch (const exception& e) {
 cerr << "处理消息错误: " << e.what() << endl;
 }
 }

 void forwardToRoomUsers(connection_hdl sender, const string& message, const string& messageType) {
 // 查找发送者所在的房间
 for (const auto& room : roomManager_.getAllRooms()) {
 auto users = roomManager_.getRoomUsers(room);
 if (users.find(sender) != users.end()) {
 // 转发给房间内其他用户
 for (auto user : users) {
 if (user.lock() != sender.lock()) {
 server_.send(user, message, frame::opcode::text);
 cout << "转发 " << messageType << " 消息给其他用户" << endl;
 }
 }
 break;
 }
 }
 }

 server_type server_;
 RoomManager roomManager_;
};

int main() {
 try {
 SignalingServer server;
 server.run(9002); // 使用9002端口
 } catch (const exception& e) {
 cerr << "服务器启动失败: " << e.what() << endl;
 return 1;
 }
 return 0;
}","instruction":"将main.cpp替换为完整的WebRTC信令服务器实现，包含WebSocket连接管理、房间管理和消息转发功能","apply_mode":"apply_only"}},"timestamp":1776760932,"type":"TOOL_CALL_ARGS"}

